const e={seo:{title:"Blog für Handwerksbetriebe | SeitenArchitekt",description:"Ratgeber für Handwerksbetriebe, die ihre Website erstellen lassen möchten: Inhalte, lokale Sichtbarkeit, Vertrauen und mehr Anfragen. Praxisnah erklärt von SeitenArchitekt."},hero:{badge:"Ratgeber · Websites für Handwerksbetriebe",titleLead:"Blog für Betriebe, die ihre",titleAccent:"Website professionell erstellen lassen",titleEnd:"möchten",copy:"Hier findest du praxisnahe Beiträge rund um Inhalte, Nutzerführung, lokale Auffindbarkeit und alles, was wichtig ist, wenn du deinen Betrieb online klar und professionell aufstellen möchtest.",primaryCta:{label:"Projekt anfragen",to:"/#kontakt"},secondaryCta:{label:"Leistungen ansehen",to:"/leistungen"},image:"/images/christopher-gower-m_HRfLhgABo-unsplash.jpg",backgroundImage:"/images/daniil-komov-RdeKfL3w344-unsplash.jpg"},intro:{label:"Einführung",title:"Worum es in diesem Blog für Website-Projekte geht",copy:"Der Blog zeigt, welche Faktoren eine Handwerker-Website heute wirklich erfolgreich machen: klare Struktur, professionelle Wirkung, mobile Nutzbarkeit und saubere Kontaktführung. So bekommst du ein besseres Gefühl dafür, worauf es ankommt, wenn du deine Website erstellen lassen willst."},listHeader:{label:"Beiträge",title:"Aktuelle Artikel"},finalCta:{title:"Du möchtest deine Website professionell planen?",copy:"Wenn du deine Website erstellen lassen möchtest und dabei Wert auf klare Inhalte, Vertrauen und Wirkung legst, lass uns dein Projekt gemeinsam planen.",primaryCta:{label:"Kontakt aufnehmen",to:"/#kontakt"},secondaryCta:{label:"Leistungsübersicht",to:"/leistungen"}},posts:[{slug:"seo-fuer-handwerker-google-berlin",category:"SEO · Handwerker",title:"SEO für Handwerker: So wirst du bei Google in Berlin gefunden",excerpt:"Lokale Suchmaschinenoptimierung erklärt – ohne technischen Fachjargon.",readingTime:"4 Min. Lesezeit",image:"/images/maik-jonietz-_yMciiStJyY-unsplash.jpg",seo:{title:"SEO für Handwerker: So wirst du bei Google in Berlin gefunden | SeitenArchitekt",description:"Lokale Suchmaschinenoptimierung für Handwerksbetriebe in Berlin verständlich erklärt."},intro:"Wer heute einen Handwerksbetrieb sucht, startet meist nicht im Branchenbuch, sondern direkt bei Google. Genau deshalb entscheidet lokale Sichtbarkeit oft darüber, ob Interessenten auf deiner Website landen oder bei einem Mitbewerber anfragen.",sections:[{title:"Warum lokale Suchanfragen so entscheidend sind",paragraphs:["Viele potenzielle Kunden suchen sehr konkret nach Leistungen und Ort – etwa nach Dachdecker, Elektriker oder Sanitär in Berlin. Wer in diesen Suchmomenten sichtbar ist, wird deutlich häufiger angefragt.","Entscheidend ist dabei nicht nur ein gutes Ranking, sondern auch eine klare Darstellung: Besucher müssen sofort erkennen, welche Leistungen du anbietest, in welcher Region du arbeitest und wie sie dich erreichen können."]},{title:"Welche Inhalte auf der Website sichtbar sein sollten",paragraphs:["Leistungsseiten sollten präzise formuliert sein und typische Kundenfragen beantworten. Je klarer du Leistungen, Einsatzgebiet und Kontaktmöglichkeiten strukturierst, desto leichter versteht Google – und vor allem der Besucher – worum es auf deiner Seite geht.","Auch Orte, Stadtteile oder Regionen sollten nur dort genannt werden, wo sie für dein Angebot wirklich relevant sind. Gute lokale Sichtbarkeit entsteht nicht durch Keyword-Stuffing, sondern durch nachvollziehbare Inhalte."]},{title:"Was Vertrauen zusätzlich stärkt",paragraphs:["Lokale SEO endet nicht bei Keywords. Referenzen, echte Ansprechpartner, schnelle Ladezeiten und eine mobil optimierte Darstellung helfen ebenfalls dabei, dass Besucher bleiben und Kontakt aufnehmen.","Wenn die Website seriös wirkt und die wichtigsten Informationen schnell erreichbar sind, steigt nicht nur die Sichtbarkeit, sondern auch die Wahrscheinlichkeit einer Anfrage."]}],bullets:["Leistungen und Einsatzgebiet klar benennen","Regionale Begriffe sinnvoll in Seitenstruktur einbauen","Website mobilfreundlich und vertrauenswürdig aufbauen"]},{slug:"5-fehler-handwerker-websites",category:"Webdesign · Tipps",title:"5 Fehler, die Handwerker-Websites häufig machen",excerpt:"Die häufigsten Probleme, die dazu führen, dass Websites keine Anfragen bringen.",readingTime:"5 Min. Lesezeit",image:"/images/christopher-gower-m_HRfLhgABo-unsplash.jpg",seo:{title:"5 Fehler, die Handwerker-Websites häufig machen | SeitenArchitekt",description:"Die häufigsten strukturellen und inhaltlichen Probleme auf Handwerker-Websites."},intro:"Viele Handwerker-Websites wirken auf den ersten Blick ordentlich – erfüllen aber ihre eigentliche Aufgabe nicht: Vertrauen aufbauen und Anfragen erleichtern. Die Ursachen sind oft wiederkehrend und lassen sich gut beheben.",sections:[{title:"1. Unklare Leistungsdarstellung",paragraphs:["Oft werden nur allgemeine Begriffe genannt, ohne konkret zu zeigen, welche Arbeiten tatsächlich angeboten werden. Besucher verstehen dann nicht sofort, ob der Betrieb für ihr Anliegen passt.","Je klarer Leistungen beschrieben werden, desto leichter fällt die Einordnung – und desto höher ist die Chance auf eine qualifizierte Kontaktaufnahme."]},{title:"2. Kein regionaler Bezug",paragraphs:["Wer lokal arbeitet, sollte das online auch deutlich machen. Fehlende Ortsbezüge erschweren es Suchmaschinen und Besuchern gleichermaßen, die Seite richtig einzuordnen.","Regionale Sichtbarkeit entsteht, wenn Leistungen und Einsatzgebiet logisch miteinander verknüpft werden."]},{title:"3. Schwache mobile Darstellung",paragraphs:["Viele Interessenten besuchen eine Handwerker-Website zuerst am Smartphone. Sind Inhalte dort schwer lesbar oder Buttons unpraktisch platziert, springen Besucher schnell wieder ab.","Mobile Optimierung ist deshalb kein Zusatz, sondern Grundlage für eine funktionierende Website."]},{title:"4. Fehlende Nutzerführung",paragraphs:["Nicht jede Website zeigt klar, was Besucher als Nächstes tun sollen. Fehlen Kontaktpunkte, klare Abschnitte oder ein nachvollziehbarer Seitenaufbau, geht Orientierung verloren.","Eine gute Nutzerführung reduziert Reibung und bringt Besucher schneller zur Anfrage."]},{title:"5. Zu viel Gestaltung, zu wenig Klarheit",paragraphs:["Ein modernes Design kann helfen – aber nur dann, wenn es die Inhalte unterstützt. Überladene Effekte oder unruhige Layouts lenken eher ab, als Vertrauen aufzubauen.","Gerade im Handwerk zählt ein seriöser, strukturierter Auftritt mehr als visuelle Show."]}],bullets:["Leistungen konkret statt allgemein beschreiben","Regionale Sichtbarkeit mitdenken","Mobile Darstellung und Nutzerführung priorisieren"]},{slug:"mobile-website-handwerker",category:"Responsive · Mobile",title:"Warum eine mobile Website für Handwerker unverzichtbar ist",excerpt:"Mehr als die Hälfte aller Suchanfragen kommen heute vom Smartphone.",readingTime:"4 Min. Lesezeit",image:"/images/daniil-komov-RdeKfL3w344-unsplash.jpg",seo:{title:"Warum eine mobile Website für Handwerker unverzichtbar ist | SeitenArchitekt",description:"Warum mobile Optimierung für Handwerksbetriebe heute unverzichtbar ist."},intro:"Die erste Begegnung mit deinem Betrieb findet online oft auf dem Smartphone statt. Genau deshalb beeinflusst die mobile Darstellung unmittelbar, wie professionell, vertrauenswürdig und erreichbar dein Unternehmen wirkt.",sections:[{title:"Der erste Eindruck entsteht mobil",paragraphs:["Wenn Texte zu klein sind, Inhalte verrutschen oder Kontaktmöglichkeiten nicht sofort sichtbar sind, wirkt selbst ein guter Betrieb online unnötig kompliziert.","Eine saubere mobile Darstellung sorgt dafür, dass Besucher schnell verstehen, was du anbietest und wie sie dich erreichen können."]},{title:"Was auf kleinen Screens besonders wichtig ist",paragraphs:["Übersichtliche Abstände, klare Typografie und kurze Wege zu Leistungen, Referenzen und Kontakt sind entscheidend. Besucher scrollen mobil anders – die Struktur muss sich diesem Verhalten anpassen.","Besonders wichtig sind starke Einstiege, klare Überschriften und ein sichtbarer Call-to-Action."]},{title:"Mobile Optimierung unterstützt auch Sichtbarkeit",paragraphs:["Nicht nur Besucher profitieren davon. Eine Website, die auf mobilen Geräten sauber funktioniert, wirkt sich auch positiv auf Wahrnehmung, Nutzbarkeit und technische Qualität aus.","Für Handwerksbetriebe ist das ein direkter Vorteil: weniger Absprünge, mehr Klarheit und bessere Voraussetzungen für neue Anfragen."]}],bullets:["Mobile Nutzerführung zuerst denken","Kontaktmöglichkeiten sofort sichtbar machen","Inhalte für kleine Screens klar strukturieren"]}]};export{e as b};
